from dataclasses import dataclass
from typing import List

@dataclass
class Triple:
    subject: str
    predicate: str
    object: str

# EVOLVE-BLOCK-START

def predict(triples: list[Triple]) -> str:
    """Convert a list of triples about a politician into a readable sentence."""
    if not triples:
        return ""

    # Get the main subject (usually the first triple's subject)
    main_subject = triples[0].subject

    # Group triples by predicate type for better sentence construction
    personal_info = []
    career_info = []
    location_info = []
    other_info = []

    for t in triples:
        if t.predicate in ["birthPlace", "birthDate", "birthYear", "deathPlace", "deathDate", "deathYear"]:
            personal_info.append(t)
        elif t.predicate in ["party", "office", "predecessor", "successor", "spouse", "nationality", "profession", "religion"]:
            career_info.append(t)
        elif t.predicate in ["country", "region", "state", "residence"]:
            location_info.append(t)
        else:
            other_info.append(t)

    # Build sentence parts
    parts = []

    # Start with basic identity
    for t in career_info:
        if t.predicate == "nationality":
            parts.append(f"{t.subject} is a {t.object}")
            break

    # Add birth information
    for t in personal_info:
        if t.predicate == "birthPlace":
            parts.append(f"who was born in {t.object}")
        elif t.predicate == "birthDate":
            parts.append(f"who was born on {t.object}")
        elif t.predicate == "birthYear":
            parts.append(f"who was born in {t.object}")

    # Add career information
    for t in career_info:
        if t.predicate == "party":
            parts.append(f"who was a member of the {t.object} party")
        elif t.predicate == "office":
            parts.append(f"who served as {t.object}")
        elif t.predicate == "spouse":
            parts.append(f"who was married to {t.object}")

    # Add location information
    for t in location_info:
        if t.predicate == "country":
            parts.append(f"from {t.object}")
        elif t.predicate == "region":
            parts.append(f"in the {t.object} region")

    # Add other information
    for t in other_info:
        if t.predicate == "successor":
            parts.append(f"and was succeeded by {t.object}")
        elif t.predicate == "predecessor":
            parts.append(f"and was preceded by {t.object}")
        elif t.predicate == "deathPlace":
            parts.append(f"and died in {t.object}")
        elif t.predicate == "deathDate":
            parts.append(f"and died on {t.object}")
        elif t.predicate == "deathYear":
            parts.append(f"and died in {t.object}")
        elif t.predicate == "battle":
            parts.append(f"who participated in the {t.object}")
        elif t.predicate == "almaMater":
            parts.append(f"who studied at {t.object}")
        elif t.predicate == "militaryBranch":
            parts.append(f"who served in the {t.object}")
        elif t.predicate == "award":
            parts.append(f"who received the {t.object}")

    # Join parts with commas and appropriate conjunctions
    if len(parts) == 1:
        return parts[0] + "."
    elif len(parts) == 2:
        return parts[0] + " " + parts[1] + "."
    else:
        # Create a more complex sentence structure
        result = main_subject + " "
        result += parts[0]
        for i, part in enumerate(parts[1:], 1):
            if i == len(parts) - 1:
                result += " and " + part
            else:
                result += ", " + part
        result += "."
        return result

